module RefModule (  
    input wire S,  
    input wire R,  
    output reg Q,  
    output reg Qn  
);  
    always @ (S or R) begin  
        if (S && !R) begin  
            Q = 1;  
            Qn = 0;  
        end  
        else if (!S && R) begin  
            Q = 0;  
            Qn = 1;  
        end  
        // if both S and R are low, hold the previous state  
    end  
endmodule
